import { mathCos as cos, mathSQRT as sqrt, mathPow as pow, mathSin as sin, mathAtan2 as atan2, mathPI as PI, mathRound as round } from "../../core/zc-constants";
import { EQUATIONS } from "../equations/zcequations";


const { midpoint, average } = EQUATIONS;
const square = x => pow(x, 2);

class PolygonPathGenerator {

    /**
     * This method generates polygon points for cubic bezier curve. i.e., `C` command in svg path.
     ** Reference: https://www.linearity.io/blog/bezier-curves/
     * @param {any[]} [points=[p0, q0, p1, q1, p2, q2, p3, q3]] 
     *  - `points[0]` is p0
     *  - `points[1]` is q0
     *  - `points[2]` is p1
     *  - `points[3]` is q1
     *  - `points[4]` is p2
     *  - `points[5]` is q2
     *  - `points[6]` is p3
     *  - `points[7]` is q3
     * @param {number} [sample=10] - contains number of samples
     * @returns {Array[]} polygon
     */
    cubic_bezier(points = [p0, q0, p1, q1, p2, q2, p3, q3], sample = 10) {
        let [p0, q0, p1, q1, p2, q2, p3, q3] = points;

        const x = EQUATIONS.cubic_bezier_curve(p0, p1, p2, p3);
        const y = EQUATIONS.cubic_bezier_curve(q0, q1, q2, q3);

        const callback = (t) => [x(t), y(t)],
            polygon = $interpolator(callback, sample, { first: true });
        return polygon;
    }

    /**
     * This method generates polygon points for arcs. i.e., `A` command in svg path.
     ** Endpoint to center parameterization
     ** Reference: https://www.w3.org/TR/SVG/implnote.html#ArcConversionEndpointToCenter
     * @param {any[]} [points=[x1, y1, rx, ry, xar, fa, fs, x2, y2]]
     * - points[0] - **x1** - x coordinate start point of the arc 
     * - points[1] - **y1** - y coordinate of the start point of the arc 
     * - points[2] - **rx** - x radius of the arc 
     * - points[3] - **ry** - y radius of the arc 
     * - points[4] - **xar** - x-axis-rotation: The angle of the x-axis rotation relative to the coordinate system, specified in degrees.
     * - points[5] - **fa** - large-arc-flag: Can be 0 or 1, where 0 means a small arc and 1 means a large arc
     * - points[6] - **fs** - sweep-flag: Can be 0 or 1, where 1 means the arc will be drawn in a positive-angle direction and 0 means the arc will be drawn in a negative-angle direction
     * - points[7] - **x2** - x coordinate of the endpoint of the arc
     * - points[8] - **y2** - y coordinate of the endpoint of the arc
     * @param {number} sample - contains number of samples
     * @returns {Array[]} polygon
     */
    arc(points = [x1, y1, rx, ry, xar, fa, fs, x2, y2], sample = 10) {
        let [x1, y1, rx, ry, xar, fa, fs, x2, y2] = points;

        //* Convert rotation to radians
        const phi = xar * PI / 180;

        const cosphi = cos(phi),
            sinphi = sin(phi);

        //* Step 1: Compute (x1', y1')
        const dx = midpoint(x1, x2),
            dy = midpoint(y1, y2),
            x1prime = (cosphi, dx) + (sinphi * dy),
            y1prime = (-sinphi * dx) + (cosphi * dy);

        //* Step 2: Find radii correction factor
        const rx_s = square(rx),
            ry_s = square(ry),
            x1prime_s = square(x1prime),
            y1prime_s = square(y1prime);

        let radiifactor = sqrt(
            ((rx_s * ry_s) - (rx_s * y1prime_s) - (ry_s * x1prime_s))
            / ((rx_s * y1prime_s) + (ry_s * x1prime_s))
        );
        radiifactor = fa === fs ? -radiifactor : radiifactor;

        //* Step 3: Compute (cx', cy')
        const cxprime = radiifactor * (rx * y1prime) / ry,
            cyprime = radiifactor * -(ry * x1prime) / rx;

        //* Step 4: Compute (cx, cy) from (cx′, cy′)
        const cx = (cosphi * cxprime) - (sinphi * cyprime) + average(x1, x2),
            cy = (sinphi * cxprime) + (cosphi * cyprime) + average(y1, y2);

        //* Step 5: Compute start angle(θ1) and (end angle)Δθ
        const theta1 = atan2((y1prime - cyprime) / ry, (x1prime - cxprime) / rx),
            theta2 = atan2((-y1prime - cyprime) / ry, (-x1prime - cxprime) / rx);

        // find theta delta and apply correction based on sweep flag
        let thetadelta = theta2 - theta1;
        thetadelta = (fs === 0 && thetadelta > 0) ? thetadelta - 2 * PI
            : (fs === 1 && thetadelta < 0) ? thetadelta + 2 * PI : thetadelta;

        const theta = t => theta1 + (thetadelta * t);

        const ArcPointGenerator = (t) => {
            const angle = theta(t),
                x = rx * cos(angle),
                y = ry * sin(angle);

            // Rotate the point back to the original coordinate system
            const x_final = cx + (cosphi * x) - (sinphi * y),
                y_final = cy + (sinphi * x) + (cosphi * y);

            return [x_final, y_final];
        }

        //* Generates polygon points based on sample
        const polygon = $interpolator(ArcPointGenerator, sample, { first: true });
        return polygon;
        // const polygon = [],
        //     step = 1 / sample,
        //     max = 1 + step;

        // for (let t = step; t <= max; t += step) {
        //     polygon.push(ArcPointGenerator(t));
        // }
        // return polygon;
    }
}

/**
 * 
 * @param {Function} callback - iterate the callback based on number of samples (t) => x(t)
 * @param {Number} sample - number of samples
 * @param {object} exclude - to exclude values in first and last points. By default excludes first point and last point
 * @param {boolean} [exclude.first=true] - exclude first value (0'th index) of the item.
 * @param {boolean} [exclude.last=true] - exclude last value(sample'th index) of the item.
 * @returns 
 */
const $interpolator = function (callback, sample, exclude = { first: false, last: false }) {
    const points = [];
    sample = round(exclude.last ? sample - 1: sample);
    for (let t = exclude.first ? 1 : 0; t <= sample; t++) {
        points.push(callback(t / sample));
    }
    return points;
}

const polygonPathGenerator = new PolygonPathGenerator();
export { polygonPathGenerator as PolygonPathGenerator };